// server/registration-window-engine.ts
function parseEventDate(dateStr) {
  const cleaned = dateStr.replace(/^(Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday),\s*/i, "");
  const parsed = new Date(cleaned);
  return isNaN(parsed.getTime()) ? null : parsed;
}
function computeRegistrationWindow(settings, isTicketed) {
  const eventDate = settings?.eventDate ? parseEventDate(settings.eventDate) : null;
  const now = /* @__PURE__ */ new Date();
  const OPEN_DAYS_BEFORE = 90;
  const CLOSE_DAYS_BEFORE = 7;
  let opensAt;
  let closesAt;
  if (eventDate) {
    opensAt = new Date(eventDate);
    opensAt.setDate(opensAt.getDate() - OPEN_DAYS_BEFORE);
    closesAt = new Date(eventDate);
    closesAt.setDate(closesAt.getDate() - CLOSE_DAYS_BEFORE);
  }
  function getStatus(forceOpen, manualClosed) {
    if (forceOpen) return { open: true, reason: "force-open" };
    if (manualClosed) return { open: false, reason: "manually-closed" };
    if (!eventDate) return { open: false, reason: "no-date-set" };
    if (now < opensAt) return { open: false, reason: "too-early" };
    if (now > closesAt) return { open: false, reason: "auto-closed" };
    return { open: true, reason: "open" };
  }
  const vendor = getStatus(settings?.vendorRegistrationForceOpen, settings?.vendorRegistrationClosed);
  const sponsor = getStatus(settings?.sponsorRegistrationForceOpen, settings?.sponsorRegistrationClosed);
  let ticketSalesOpen = false;
  let ticketReason = "no-date-set";
  if (isTicketed) {
    if (settings?.ticketSalesForceOpen) {
      ticketSalesOpen = true;
      ticketReason = "force-open";
    } else if (settings?.ticketSalesClosed) {
      ticketSalesOpen = false;
      ticketReason = "manually-closed";
    } else {
      ticketSalesOpen = true;
      ticketReason = "open";
    }
  }
  return {
    vendorOpen: vendor.open,
    sponsorOpen: sponsor.open,
    ticketSalesOpen,
    eventDate: settings?.eventDate || null,
    opensAt: opensAt?.toISOString(),
    closesAt: closesAt?.toISOString(),
    reason: vendor.reason
  };
}

// server/content-hooks.ts
function fireHook(config3, event, strategy, data) {
  if (!config3.pillarWebhookUrl) return;
  const payload = {
    event,
    orgName: config3.orgName,
    orgWebsite: config3.orgWebsite || "",
    timestamp: (/* @__PURE__ */ new Date()).toISOString(),
    strategy,
    data
  };
  const controller = new AbortController();
  setTimeout(() => controller.abort(), 5e3);
  fetch(config3.pillarWebhookUrl, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Content-Hook": event,
      "X-Content-Priority": strategy.priority,
      "X-Content-Category": strategy.category
    },
    body: JSON.stringify(payload),
    signal: controller.signal
  }).catch(() => {
  });
}
function createContentHook(config3) {
  return {
    eventActivated(event) {
      fireHook(config3, "event.activated", {
        priority: "high",
        category: "announcement",
        suggestedPlatforms: ["x", "facebook", "instagram"],
        postImmediately: false,
        suggestedTone: "exciting, inviting",
        includeImage: true,
        includeLink: true,
        threadWorthy: false,
        cadenceKey: null,
        cadenceLimitPerDay: null
      }, event);
    },
    eventUpdated(event, changedFields) {
      const dateOrTimeChanged = changedFields.includes("date") || changedFields.includes("time");
      fireHook(config3, "event.updated", {
        priority: dateOrTimeChanged ? "high" : "normal",
        category: "update",
        suggestedPlatforms: ["x", "facebook"],
        postImmediately: dateOrTimeChanged,
        suggestedTone: "informative, urgent",
        includeImage: false,
        includeLink: true,
        threadWorthy: false,
        cadenceKey: null,
        cadenceLimitPerDay: null
      }, { ...event, changedFields });
    },
    ticketSalesOpened(event) {
      fireHook(config3, "ticket_sales.opened", {
        priority: "high",
        category: "announcement",
        suggestedPlatforms: ["x", "facebook", "instagram"],
        postImmediately: false,
        suggestedTone: "exciting, promotional",
        includeImage: true,
        includeLink: true,
        threadWorthy: false,
        cadenceKey: null,
        cadenceLimitPerDay: null
      }, event);
    },
    ticketPurchased(event, totalSold, capacity) {
      const milestones = [10, 25, 50, 75, 100, 150, 200, 250, 500];
      const pct = capacity ? totalSold / capacity * 100 : 0;
      if (milestones.includes(totalSold)) {
        const priority = pct >= 80 ? "high" : "normal";
        fireHook(config3, "ticket_sales.milestone", {
          priority,
          category: "milestone",
          suggestedPlatforms: pct >= 80 ? ["x", "facebook", "instagram"] : ["facebook"],
          postImmediately: pct >= 80,
          suggestedTone: pct >= 80 ? "urgent, scarcity" : "celebratory",
          includeImage: false,
          includeLink: true,
          threadWorthy: false,
          cadenceKey: "ticket_milestone",
          cadenceLimitPerDay: 1
        }, { ...event, totalSold, capacity, percentSold: pct.toFixed(0) });
      }
      if (capacity && totalSold >= capacity) {
        fireHook(config3, "ticket_sales.sold_out", {
          priority: "urgent",
          category: "announcement",
          suggestedPlatforms: ["x", "facebook", "instagram"],
          postImmediately: true,
          suggestedTone: "excited, urgent",
          includeImage: false,
          includeLink: false,
          threadWorthy: false,
          cadenceKey: null,
          cadenceLimitPerDay: null
        }, { ...event, totalSold, capacity });
      }
      fireHook(config3, "ticket.purchased", {
        priority: "low",
        category: "internal",
        suggestedPlatforms: [],
        postImmediately: false,
        suggestedTone: "",
        includeImage: false,
        includeLink: false,
        threadWorthy: false,
        cadenceKey: null,
        cadenceLimitPerDay: null
      }, { ...event, totalSold });
    },
    blogPublished(post) {
      const cat = (post.category || "").toLowerCase();
      const toneMap = { recap: "reflective, celebratory", spotlight: "warm, personal", "press release": "professional", announcement: "exciting" };
      const tone = toneMap[cat] || "informative, engaging";
      const threadWorthy = (post.excerpt?.length || 0) > 200;
      fireHook(config3, "blog.published", {
        priority: "high",
        category: "announcement",
        suggestedPlatforms: ["x", "facebook", "instagram"],
        postImmediately: false,
        suggestedTone: tone,
        includeImage: !!post.coverImageUrl,
        includeLink: true,
        threadWorthy,
        cadenceKey: null,
        cadenceLimitPerDay: null
      }, post);
    },
    vendorRegistered(reg) {
      fireHook(config3, "vendor.registered", {
        priority: "low",
        category: "internal",
        suggestedPlatforms: [],
        postImmediately: false,
        suggestedTone: "",
        includeImage: false,
        includeLink: false,
        threadWorthy: false,
        cadenceKey: null,
        cadenceLimitPerDay: null
      }, reg);
    },
    sponsorAdded(sponsor) {
      const isPremium = sponsor.level.toLowerCase().includes("presenting") || sponsor.level.toLowerCase().includes("gold");
      fireHook(config3, "sponsor.added", {
        priority: isPremium ? "high" : "normal",
        category: "recognition",
        suggestedPlatforms: isPremium ? ["x", "facebook", "instagram"] : ["facebook"],
        postImmediately: false,
        suggestedTone: "grateful, professional",
        includeImage: false,
        includeLink: true,
        threadWorthy: false,
        cadenceKey: "sponsor_shoutout",
        cadenceLimitPerDay: 2
      }, sponsor);
    }
  };
}

