async function startServer() {
  await runMigrations();
  registerRoutes(app);
  if (process.env.NODE_ENV === "production") {
    const staticPath = path.join(__dirname, "../public");
    const indexHtmlPath = path.join(staticPath, "index.html");
    app.use(import_express4.default.static(staticPath));
    app.get("*", (req, res) => {
      try {
        if (path.extname(req.path)) {
          res.status(404).type("text/plain").send("Static asset not found");
          return;
        }
        res.setHeader("Content-Type", "text/html; charset=utf-8");
        res.setHeader("Cache-Control", "no-cache, no-store");
        res.sendFile(indexHtmlPath);
      } catch {
        res.status(500).send("Failed to load application");
      }
    });
  } else {
    app.get("/assets/*", (req, res, next) => {
      if (!path.extname(req.path)) {
        next();
        return;
      }
      res.status(404).type("text/plain").send("Static asset not found");
    });
    const { createServer: createViteServer } = await import("vite");
    const vite = await createViteServer({
      root: path.join(__dirname, ".."),
      server: { middlewareMode: true },
      appType: "spa"
    });
    app.use(vite.middlewares);
  }
  try {
    const { execSync } = await import("child_process");
    execSync(`fuser -k ${PORT}/tcp`, { stdio: "ignore" });
  } catch {
  }
  const server = createServer(app);
  server.listen(PORT, "0.0.0.0", () => {
    console.log(`Community platform listening on port ${PORT}`);
  });
  server.on("error", (err) => {
    if (err.code === "EADDRINUSE") {
      console.error(`Port ${PORT} is already in use. Kill the existing process and restart.`);
      process.exit(1);
    }
    throw err;
  });
}
startServer().catch(console.error);
